'use client'

import { useState, useEffect } from 'react'
import { cn } from '@/lib/utils'
import { useI18n } from '@/lib/i18n-context'

export default function Navbar() {
  const { locale, t, setLocale } = useI18n()
  const [scrolled, setScrolled] = useState(false)
  const [menuOpen, setMenuOpen] = useState(false)

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40)
    window.addEventListener('scroll', onScroll)
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  const navLinks = [
    { label: t.nav.solutions, href: '#solutions' },
    { label: t.nav.framework, href: '#framework' },
    { label: t.nav.platform, href: '#platform' },
    { label: t.nav.about, href: '#about' },
  ]

  return (
    <header
      className={cn(
        'fixed top-0 left-0 right-0 z-50 transition-all duration-400',
        scrolled
          ? 'bg-forest-950/96 backdrop-blur-md border-b border-sage/15 py-3'
          : 'bg-transparent py-5'
      )}
    >
      <nav className="max-w-7xl mx-auto px-6 lg:px-12 flex items-center justify-between">
        {/* ─── Logo ─── */}
        <a href="#" className="flex items-center gap-2.5 group">
          <div className="w-8 h-8">
            <svg viewBox="0 0 32 32" fill="none" className="w-full h-full">
              {/* A friendly "+" / nexus mark */}
              <circle cx="16" cy="16" r="14" stroke="#5c8f72" strokeWidth="1.5" strokeOpacity="0.5" />
              <line x1="6" y1="6" x2="26" y2="26" stroke="#c8975a" strokeWidth="2" strokeLinecap="round"
                className="transition-opacity group-hover:opacity-60" />
              <line x1="26" y1="6" x2="6" y2="26" stroke="#c8975a" strokeWidth="2" strokeLinecap="round"
                className="transition-opacity group-hover:opacity-60" />
              <circle cx="16" cy="16" r="3" fill="#c8975a" />
            </svg>
          </div>
          <span className="font-display text-xl font-semibold tracking-wide">
            <span className="text-cream">Px</span>
            <span className="text-sage-light">Nexus</span>
          </span>
        </a>

        {/* ─── Desktop nav ─── */}
        <ul className="hidden lg:flex items-center gap-7">
          {navLinks.map((link) => (
            <li key={link.label}>
              <a
                href={link.href}
                className="font-body text-sm text-cream/55 hover:text-cream transition-colors relative group"
              >
                {link.label}
                <span className="absolute -bottom-1 left-0 w-0 h-px bg-sage transition-all duration-300 group-hover:w-full" />
              </a>
            </li>
          ))}
        </ul>

        {/* ─── Right actions ─── */}
        <div className="hidden lg:flex items-center gap-3">
          {/* Language toggle */}
          <div className="flex items-center gap-1 border border-sage/20 rounded-full px-1 py-1">
            <button
              onClick={() => setLocale('en')}
              className={cn(
                'font-body text-xs px-2.5 py-1 rounded-full transition-all duration-200',
                locale === 'en'
                  ? 'bg-sage text-forest-900 font-medium'
                  : 'text-cream/50 hover:text-cream'
              )}
            >
              EN
            </button>
            <button
              onClick={() => setLocale('ja')}
              className={cn(
                'font-body text-xs px-2.5 py-1 rounded-full transition-all duration-200',
                locale === 'ja'
                  ? 'bg-sage text-forest-900 font-medium'
                  : 'text-cream/50 hover:text-cream'
              )}
            >
              日本語
            </button>
          </div>

          <a
            href="#contact"
            className="font-body text-sm text-cream/55 hover:text-cream transition-colors"
          >
            {t.nav.signIn}
          </a>
          <a
            href="#contact"
            className="btn-shimmer font-body text-sm font-medium px-5 py-2.5 rounded-lg bg-sage text-forest-900 hover:bg-sage-light transition-colors duration-200"
          >
            {t.nav.requestDemo}
          </a>
        </div>

        {/* ─── Mobile hamburger ─── */}
        <div className="lg:hidden flex items-center gap-3">
          {/* Mobile lang toggle */}
          <div className="flex items-center gap-0.5 border border-sage/20 rounded-full px-1 py-1">
            <button
              onClick={() => setLocale('en')}
              className={cn(
                'font-body text-xs px-2 py-0.5 rounded-full transition-all',
                locale === 'en' ? 'bg-sage text-forest-900' : 'text-cream/50'
              )}
            >
              EN
            </button>
            <button
              onClick={() => setLocale('ja')}
              className={cn(
                'font-body text-xs px-2 py-0.5 rounded-full transition-all',
                locale === 'ja' ? 'bg-sage text-forest-900' : 'text-cream/50'
              )}
            >
              JP
            </button>
          </div>
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className="flex flex-col gap-1.5 p-2"
            aria-label="Toggle menu"
          >
            <span className={cn('w-5 h-px bg-cream transition-all duration-300', menuOpen && 'rotate-45 translate-y-2')} />
            <span className={cn('w-5 h-px bg-cream transition-all duration-300', menuOpen && 'opacity-0')} />
            <span className={cn('w-5 h-px bg-cream transition-all duration-300', menuOpen && '-rotate-45 -translate-y-2')} />
          </button>
        </div>
      </nav>

      {/* ─── Mobile menu ─── */}
      <div className={cn(
        'lg:hidden overflow-hidden transition-all duration-300',
        menuOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
      )}>
        <div className="bg-forest-900/98 backdrop-blur-md border-t border-sage/10 px-6 py-5 flex flex-col gap-3">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              onClick={() => setMenuOpen(false)}
              className="font-body text-sm text-cream/65 hover:text-cream py-1.5"
            >
              {link.label}
            </a>
          ))}
          <div className="pt-3 border-t border-sage/10">
            <a
              href="#contact"
              onClick={() => setMenuOpen(false)}
              className="block w-full text-center font-body text-sm font-medium px-5 py-3 rounded-lg bg-sage text-forest-900"
            >
              {t.nav.requestDemo}
            </a>
          </div>
        </div>
      </div>
    </header>
  )
}
