'use client'

import { useEffect, useRef } from 'react'
import { useI18n } from '@/lib/i18n-context'

export default function TrustBanner() {
  const { t } = useI18n()
  const sectionRef = useRef<HTMLElement>(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => entries.forEach((e) => e.isIntersecting && e.target.classList.add('visible')),
      { threshold: 0.08 }
    )
    sectionRef.current?.querySelectorAll('.reveal').forEach((el) => observer.observe(el))
    return () => observer.disconnect()
  }, [])

  return (
    <section
      id="about"
      ref={sectionRef}
      className="relative bg-forest-950 py-24 lg:py-36 overflow-hidden"
    >
      {/* Soft green ambient glow */}
      <div
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[400px] pointer-events-none opacity-[0.06]"
        style={{ background: 'radial-gradient(ellipse, #5c8f72 0%, transparent 70%)' }}
      />

      {/* Top line */}
      <div
        className="absolute top-0 left-0 right-0 h-px"
        style={{ background: 'linear-gradient(90deg, transparent, rgba(92,143,114,0.4) 20%, rgba(92,143,114,0.6) 50%, rgba(92,143,114,0.4) 80%, transparent)' }}
      />

      <div className="max-w-7xl mx-auto px-6 lg:px-12">
        {/* ─── Eyebrow ─── */}
        <div className="reveal text-center mb-12">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-sage/10 border border-sage/20">
            <span className="font-body text-xs text-sage-muted tracking-widest uppercase">
              {t.trust.eyebrow}
            </span>
          </div>
        </div>

        {/* ─── Founder quote ─── */}
        <div className="reveal text-center mb-16 lg:mb-20">
          {/* Open quote */}
          <div className="font-display text-[96px] leading-none text-sage/10 select-none mb-[-2rem]">"</div>

          <blockquote className="font-display text-2xl sm:text-3xl lg:text-4xl font-light text-cream/85 leading-[1.3] max-w-3xl mx-auto mb-7 italic">
            {t.trust.quote}
          </blockquote>

          <div className="flex items-center justify-center gap-2">
            <div className="w-6 h-px bg-sage/30" />
            <span className="font-body text-sm text-cream/35">{t.trust.attribution}</span>
            <div className="w-6 h-px bg-sage/30" />
          </div>
        </div>

        {/* ─── Stats grid ─── */}
        <div className="reveal grid grid-cols-2 lg:grid-cols-4 gap-px bg-forest-700/20 rounded-2xl overflow-hidden mb-16">
          {t.trust.stats.map((stat) => (
            <div
              key={stat.label}
              className="group bg-forest-900 hover:bg-forest-800 transition-colors duration-300 p-8 lg:p-10 text-center"
            >
              <div className="font-display text-4xl lg:text-5xl font-light text-sage-light mb-2 group-hover:scale-105 transition-transform duration-300 origin-bottom">
                {stat.value}
              </div>
              <div className="font-body text-sm font-medium text-cream/70 mb-1">
                {stat.label}
              </div>
              <div className="font-body text-xs text-cream/30">
                {stat.sub}
              </div>
            </div>
          ))}
        </div>

        {/* ─── Testimonials ─── */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
          {t.trust.testimonials.map((item, i) => (
            <div
              key={i}
              className="reveal group p-7 lg:p-8 rounded-2xl border border-sage/10 hover:border-sage/22 hover:bg-forest-900/60 transition-all duration-300"
              style={{ transitionDelay: `${i * 0.12}s` }}
            >
              {/* Stars */}
              <div className="flex gap-0.5 mb-4">
                {[...Array(5)].map((_, s) => (
                  <svg key={s} viewBox="0 0 12 12" fill="none" className="w-3.5 h-3.5">
                    <path d="M6 1l1.2 2.6 2.8.4-2 2 .5 2.8L6 7.5 3.5 8.8l.5-2.8-2-2 2.8-.4L6 1z" fill="#c8975a" />
                  </svg>
                ))}
              </div>

              <p className="font-display text-xl lg:text-2xl font-light italic text-cream/75 leading-relaxed mb-6">
                "{item.quote}"
              </p>

              <div className="flex items-center gap-3">
                {/* Avatar initials */}
                <div className="w-9 h-9 rounded-full bg-sage/15 border border-sage/20 flex items-center justify-center">
                  <span className="font-body text-xs font-semibold text-sage-light">
                    {item.author.charAt(0)}
                  </span>
                </div>
                <div>
                  <div className="font-body text-sm font-medium text-cream/70">{item.author}</div>
                  <div className="font-body text-xs text-cream/35">{item.role}</div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* ─── Trust logos placeholder ─── */}
        <div className="reveal mt-16 text-center">
          <p className="font-body text-xs text-cream/25 tracking-widest uppercase mb-7">
            Trusted by teams at
          </p>
          <div className="flex flex-wrap items-center justify-center gap-8 lg:gap-14 opacity-30">
            {['Brightloop', 'Meridian Co.', 'Tanaka Group', 'Foresta Inc.', 'Openfield HR'].map((name) => (
              <span key={name} className="font-display text-lg font-light text-cream/60">
                {name}
              </span>
            ))}
          </div>
        </div>
      </div>
    </section>
  )
}
