'use client'

import { useEffect, useRef } from 'react'
import { useI18n } from '@/lib/i18n-context'

const featureIcons = [
  <svg key="1" viewBox="0 0 20 20" fill="none" className="w-5 h-5">
    <circle cx="10" cy="10" r="3" stroke="currentColor" strokeWidth="1.5" />
    <path d="M10 2v2M10 16v2M2 10h2M16 10h2M4.3 4.3l1.4 1.4M14.3 14.3l1.4 1.4M4.3 15.7l1.4-1.4M14.3 5.7l1.4-1.4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>,
  <svg key="2" viewBox="0 0 20 20" fill="none" className="w-5 h-5">
    <path d="M10 18s-7-5.4-7-10a7 7 0 0114 0c0 4.6-7 10-7 10z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" />
    <circle cx="10" cy="8" r="2.5" stroke="currentColor" strokeWidth="1.5" />
  </svg>,
  <svg key="3" viewBox="0 0 20 20" fill="none" className="w-5 h-5">
    <path d="M3 14l3.5-5 3 3.5L13 7l4 7H3z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" />
  </svg>,
  <svg key="4" viewBox="0 0 20 20" fill="none" className="w-5 h-5">
    <rect x="2" y="5" width="16" height="10" rx="2" stroke="currentColor" strokeWidth="1.5" />
    <path d="M6 10h8M10 7v6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>,
]

export default function TechNexus() {
  const { t } = useI18n()
  const sectionRef = useRef<HTMLElement>(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => entries.forEach((e) => e.isIntersecting && e.target.classList.add('visible')),
      { threshold: 0.07 }
    )
    sectionRef.current?.querySelectorAll('.reveal').forEach((el) => observer.observe(el))
    return () => observer.disconnect()
  }, [])

  return (
    <section
      id="platform"
      ref={sectionRef}
      className="relative bg-forest-900 py-24 lg:py-36 overflow-hidden"
    >
      {/* Subtle background pattern */}
      <div
        className="absolute inset-0 opacity-[0.025]"
        style={{
          backgroundImage: 'linear-gradient(rgba(92,143,114,0.8) 1px, transparent 1px), linear-gradient(90deg, rgba(92,143,114,0.8) 1px, transparent 1px)',
          backgroundSize: '56px 56px',
        }}
      />

      <div className="max-w-7xl mx-auto px-6 lg:px-12">
        {/* ─── Header ─── */}
        <div className="reveal text-center mb-14 lg:mb-20">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-sage/10 border border-sage/20 mb-6">
            <span className="font-body text-xs text-sage-muted tracking-widest uppercase">
              {t.tech.eyebrow}
            </span>
          </div>
          <h2 className="font-display text-4xl sm:text-5xl lg:text-6xl font-light text-cream leading-tight mb-4">
            {t.tech.headline}
          </h2>
          <p className="font-body text-base sm:text-lg text-cream/45 max-w-xl mx-auto leading-relaxed">
            {t.tech.sub}
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-16 items-center">
          {/* ─── Visualization ─── */}
          <div className="reveal order-2 lg:order-1">
            <div className="rounded-2xl p-px"
              style={{ background: 'linear-gradient(135deg, rgba(92,143,114,0.3), rgba(92,143,114,0.05), rgba(200,151,90,0.2))' }}
            >
              <div className="bg-forest-950 rounded-2xl p-6 lg:p-8">
                <svg viewBox="0 0 380 300" fill="none" className="w-full">
                  <defs>
                    <linearGradient id="p-company" x1="0%" y1="0%" x2="100%" y2="100%">
                      <stop offset="0%" stopColor="#5c8f72" stopOpacity="0.9" />
                      <stop offset="100%" stopColor="#5c8f72" stopOpacity="0.2" />
                    </linearGradient>
                    <linearGradient id="p-talent" x1="100%" y1="0%" x2="0%" y2="100%">
                      <stop offset="0%" stopColor="#c8975a" stopOpacity="0.9" />
                      <stop offset="100%" stopColor="#c8975a" stopOpacity="0.2" />
                    </linearGradient>
                    <radialGradient id="p-center" cx="50%" cy="50%" r="50%">
                      <stop offset="0%" stopColor="#eecf94" stopOpacity="0.9" />
                      <stop offset="60%" stopColor="#c8975a" stopOpacity="0.4" />
                      <stop offset="100%" stopColor="transparent" stopOpacity="0" />
                    </radialGradient>
                    <filter id="p-glow">
                      <feGaussianBlur stdDeviation="5" result="blur" />
                      <feComposite in="SourceGraphic" in2="blur" operator="over" />
                    </filter>
                  </defs>

                  {/* Company node */}
                  <circle cx="68" cy="66" r="38" fill="rgba(92,143,114,0.07)" stroke="rgba(92,143,114,0.3)" strokeWidth="1" />
                  <circle cx="68" cy="66" r="24" fill="rgba(92,143,114,0.12)" />
                  <text x="68" y="62" textAnchor="middle" fill="#7db090" fontSize="8" fontFamily="DM Sans, system-ui" fontWeight="600">COMPANY</text>
                  <text x="68" y="74" textAnchor="middle" fill="rgba(92,143,114,0.5)" fontSize="7" fontFamily="DM Sans, system-ui">Culture · Goals</text>

                  {/* Talent node */}
                  <circle cx="312" cy="66" r="38" fill="rgba(200,151,90,0.07)" stroke="rgba(200,151,90,0.3)" strokeWidth="1" />
                  <circle cx="312" cy="66" r="24" fill="rgba(200,151,90,0.12)" />
                  <text x="312" y="62" textAnchor="middle" fill="#ddb07a" fontSize="8" fontFamily="DM Sans, system-ui" fontWeight="600">TALENT</text>
                  <text x="312" y="74" textAnchor="middle" fill="rgba(200,151,90,0.5)" fontSize="7" fontFamily="DM Sans, system-ui">Skills · Values</text>

                  {/* Converging paths */}
                  <path className="nexus-line" d="M90 85 Q145 150 183 208"
                    stroke="url(#p-company)" strokeWidth="1.5" strokeLinecap="round" fill="none" />
                  <path className="nexus-line nexus-line-delay" d="M290 85 Q235 150 197 208"
                    stroke="url(#p-talent)" strokeWidth="1.5" strokeLinecap="round" fill="none" />

                  {/* Center nexus point */}
                  <circle cx="190" cy="218" r="28" fill="url(#p-center)" opacity="0.15" filter="url(#p-glow)" />
                  <circle cx="190" cy="218" r="18" fill="rgba(92,143,114,0.1)" stroke="rgba(92,143,114,0.4)" strokeWidth="1" />
                  <circle cx="190" cy="218" r="5" fill="#eecf94" className="nexus-dot" />
                  <text x="190" y="215" textAnchor="middle" fill="#eecf94" fontSize="7.5" fontFamily="DM Sans, system-ui" fontWeight="600">PxNexus</text>
                  <text x="190" y="228" textAnchor="middle" fill="rgba(240,207,148,0.55)" fontSize="6.5" fontFamily="DM Sans, system-ui">The Match</text>

                  {/* Score badges */}
                  {[{ x: 128, y: 188, val: 'Fit: 94%', color: '#7db090' }, { x: 248, y: 188, val: '★ 4.8', color: '#ddb07a' }].map((b) => (
                    <g key={b.x}>
                      <rect x={b.x - 22} y={b.y - 9} width="44" height="18" rx="4"
                        fill="rgba(23,48,32,0.8)" stroke={`${b.color}40`} strokeWidth="0.75" />
                      <text x={b.x} y={b.y + 4} textAnchor="middle" fill={b.color} fontSize="7.5"
                        fontFamily="DM Sans, system-ui" fontWeight="600">{b.val}</text>
                    </g>
                  ))}

                  {/* Output */}
                  <path className="nexus-line" d="M190 236 L190 278"
                    stroke="rgba(92,143,114,0.35)" strokeWidth="1" strokeLinecap="round"
                    strokeDasharray="3 3" fill="none" />
                  <text x="190" y="290" textAnchor="middle" fill="rgba(92,143,114,0.5)"
                    fontSize="7.5" fontFamily="DM Sans, system-ui">Placement + Onboarding</text>
                </svg>

                {/* Stats */}
                <div className="mt-5 grid grid-cols-3 gap-4 border-t border-sage/10 pt-5">
                  {t.tech.stats.map((s) => (
                    <div key={s.label} className="text-center">
                      <div className="font-display text-xl font-medium text-amber">{s.value}</div>
                      <div className="font-body text-xs text-cream/35 mt-0.5">{s.label}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>

          {/* ─── Features ─── */}
          <div className="order-1 lg:order-2 space-y-4">
            {t.tech.features.map((feature, i) => (
              <div
                key={feature.title}
                className="reveal group flex gap-4 p-5 rounded-xl border border-sage/10 hover:border-sage/25 hover:bg-forest-800/40 transition-all duration-300"
                style={{ transitionDelay: `${i * 0.1}s` }}
              >
                <div className="flex-shrink-0 w-10 h-10 rounded-lg bg-sage/10 flex items-center justify-center text-sage group-hover:bg-sage/18 transition-colors">
                  {featureIcons[i]}
                </div>
                <div>
                  <h4 className="font-body text-sm font-semibold text-cream mb-1.5">{feature.title}</h4>
                  <p className="font-body text-sm text-cream/42 leading-relaxed">{feature.description}</p>
                </div>
              </div>
            ))}

            <div className="reveal pt-3">
              <a
                href="#contact"
                className="btn-shimmer inline-flex items-center gap-2.5 font-body text-sm font-medium px-6 py-3.5 rounded-xl bg-sage/10 border border-sage/25 text-sage hover:bg-sage hover:text-forest-900 transition-all duration-300"
              >
                {t.tech.cta}
                <svg className="w-4 h-4" viewBox="0 0 16 16" fill="none">
                  <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </a>
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}
